```
static struct attribute *tb_egpu_qwd_attrs[] = {
    &dev_attr_tb_egpu_qwd_cycles.attr,
    &dev_attr_tb_egpu_qwd_detections.attr,
    &dev_attr_tb_egpu_qwd_last_detection_jiffies.attr,
